const form=document.getElementById("carFilterForm");const car_filter_form_brand=document.getElementById("car_filter_form_brand");const car_filter_form_model=document.getElementById("car_filter_form_model");const car_filter_form_generation=document.getElementById("car_filter_form_generation");const car_filter_form_petrol=document.getElementById("car_filter_form_petrol");const updateForm=async(data,url,method)=>{const req=await fetch(url,{method:method,body:data,headers:{"Content-Type":"application/x-www-form-urlencoded",charset:"utf-8"}});return await req.text()};const parseTextToHtml=text=>{const parser=new DOMParser;return parser.parseFromString(text,"text/html")};const handleBrandChange=async e=>{const formData=new FormData;formData.append("car_filter_form[brand]",e.target.value);try{const response=await fetch(form.action,{method:"POST",body:new URLSearchParams(formData),headers:{"Content-Type":"application/x-www-form-urlencoded","X-Requested-With":"XMLHttpRequest"}});if(false===response.ok){throw new Error("Network error")}const html=await response.text();const doc=parseTextToHtml(html);const newModelSelect=doc.getElementById("car_filter_form_model");if(newModelSelect){car_filter_form_model.innerHTML=newModelSelect.innerHTML;car_filter_form_model.disabled=newModelSelect.disabled;car_filter_form_generation.innerHTML=doc.getElementById("car_filter_form_generation").innerHTML;car_filter_form_generation.disabled=doc.getElementById("car_filter_form_generation").disabled;car_filter_form_petrol.innerHTML=doc.getElementById("car_filter_form_petrol").innerHTML;car_filter_form_petrol.disabled=doc.getElementById("car_filter_form_petrol").disabled}}catch(error){console.error("Error:",error)}};const handleModelChange=async e=>{const formData=new FormData;formData.append("car_filter_form[brand]",car_filter_form_brand.value);formData.append("car_filter_form[model]",e.target.value);try{const response=await fetch(form.action,{method:"POST",body:new URLSearchParams(formData),headers:{"Content-Type":"application/x-www-form-urlencoded","X-Requested-With":"XMLHttpRequest"}});if(false===response.ok){throw new Error("Network error")}const html=await response.text();const doc=parseTextToHtml(html);const newGenerationSelect=doc.getElementById("car_filter_form_generation");if(newGenerationSelect){car_filter_form_generation.innerHTML=newGenerationSelect.innerHTML;car_filter_form_generation.disabled=newGenerationSelect.disabled;car_filter_form_petrol.innerHTML=doc.getElementById("car_filter_form_petrol").innerHTML;car_filter_form_petrol.disabled=doc.getElementById("car_filter_form_petrol").disabled}}catch(error){console.error("Error:",error)}};const handleGenerationChange=async e=>{const formData=new FormData;formData.append("car_filter_form[brand]",car_filter_form_brand.value);formData.append("car_filter_form[model]",car_filter_form_model.value);formData.append("car_filter_form[generation]",e.target.value);try{const response=await fetch(form.action,{method:"POST",body:new URLSearchParams(formData),headers:{"Content-Type":"application/x-www-form-urlencoded","X-Requested-With":"XMLHttpRequest"}});if(false===response.ok){throw new Error("Network error")}const html=await response.text();const doc=parseTextToHtml(html);const newPetrolSelect=doc.getElementById("car_filter_form_petrol");if(newPetrolSelect){car_filter_form_petrol.innerHTML=newPetrolSelect.innerHTML;car_filter_form_petrol.disabled=newPetrolSelect.disabled}}catch(error){console.error("Error:",error)}};car_filter_form_brand.addEventListener("change",handleBrandChange);car_filter_form_model.addEventListener("change",handleModelChange);car_filter_form_generation.addEventListener("change",handleGenerationChange);